## Validation & Tests

### Unit Tests
```rust
#[test]
fn test_ndcg_perfect_ranking() {
    let relevance = vec![true, true, true, false, false];
    let ndcg = compute_ndcg(&relevance, 5);
    assert!((ndcg - 1.0).abs() < 0.01, "Perfect ranking should give NDCG=1.0");
}

#[test]
fn test_ndcg_worst_ranking() {
    let relevance = vec![false, false, false, true, true];
    let ndcg = compute_ndcg(&relevance, 5);
    assert!(ndcg < 0.7, "Worst ranking should have low NDCG: {}", ndcg);
}

#[test]
fn test_mrr_first_relevant_at_position_1() {
    let relevance = vec![true, false, false];
    assert_eq!(compute_mrr(&relevance), 1.0);
}

#[test]
fn test_mrr_first_relevant_at_position_3() {
    let relevance = vec![false, false, true];
    assert!((compute_mrr(&relevance) - 1.0/3.0).abs() < 0.01);
}

#[test]
fn test_pct_lift_positive() {
    assert!((pct_lift(0.5, 0.6) - 20.0).abs() < 0.01);
}

#[test]
fn test_pct_lift_negative() {
    assert!((pct_lift(0.5, 0.4) - (-20.0)).abs() < 0.01);
}

#[test]
fn test_pct_lift_zero_baseline() {
    assert_eq!(pct_lift(0.0, 0.5), 0.0);
}

#[test]
fn test_bootstrap_significance_clear_improvement() {
    let baseline = vec![0.3, 0.4, 0.35, 0.38, 0.42];
    let improved = vec![0.7, 0.8, 0.75, 0.78, 0.82];
    let (ci_low, ci_high, significant) = bootstrap_significance(&baseline, &improved, 1000);
    assert!(significant, "Clear improvement should be significant");
    assert!(ci_low > 0.0);
}

#[test]
fn test_query_category_classification() {
    assert_eq!(classify_query("machine learning"), QueryCategory::Short);
    assert_eq!(classify_query("how to optimize neural networks"), QueryCategory::Question);
    assert_eq!(classify_query("ONNX runtime"), QueryCategory::Keyword);
}
