// src/benchmark/rerank_quality.rs
pub struct RerankQualityBenchmark {
    corpus: TestCorpus,
    queries: Vec<LabeledQuery>,
    embedders: Vec<Box<dyn Embedder>>,
    rerankers: Vec<Box<dyn Reranker>>,
}

#[derive(Debug, Serialize)]
pub struct QualityReport {
    pub embedder: String,
    pub reranker: String,
    pub metrics: MetricsAtK,
    pub lift_over_baseline: LiftMetrics,
    pub by_query_category: HashMap<QueryCategory, MetricsAtK>,
    pub latency: LatencyStats,
}

#[derive(Debug, Serialize)]
pub struct MetricsAtK {
    pub ndcg_5: f64,
    pub ndcg_10: f64,
    pub ndcg_20: f64,
    pub mrr: f64,
    pub map_10: f64,
    pub precision_1: f64,
    pub precision_3: f64,
    pub precision_5: f64,
    pub precision_10: f64,
    pub recall_10: f64,
    pub recall_20: f64,
    pub recall_50: f64,
    pub recall_100: f64,
}

#[derive(Debug, Serialize)]
pub struct LiftMetrics {
    pub ndcg_10_lift_pct: f64,
    pub mrr_lift_pct: f64,
    pub precision_5_lift_pct: f64,
}

impl RerankQualityBenchmark {
    pub fn run(&self) -> Result<Vec<QualityReport>> {
        let mut reports = Vec::new();

        for embedder in &self.embedders {
            // Baseline: semantic search without reranking
            let baseline = self.evaluate_pipeline(embedder.as_ref(), None)?;
            tracing::info!(
                embedder = embedder.model_name(),
                ndcg_10 = baseline.metrics.ndcg_10,
                mrr = baseline.metrics.mrr,
                "Baseline (no rerank)"
            );

            for reranker in &self.rerankers {
                let result = self.evaluate_pipeline(embedder.as_ref(), Some(reranker.as_ref()))?;

                let lift = LiftMetrics {
                    ndcg_10_lift_pct: pct_lift(baseline.metrics.ndcg_10, result.metrics.ndcg_10),
                    mrr_lift_pct: pct_lift(baseline.metrics.mrr, result.metrics.mrr),
                    precision_5_lift_pct: pct_lift(baseline.metrics.precision_5, result.metrics.precision_5),
                };

                tracing::info!(
                    embedder = embedder.model_name(),
                    reranker = reranker.model_name(),
                    ndcg_10 = result.metrics.ndcg_10,
                    ndcg_lift = format!("{:+.1}%", lift.ndcg_10_lift_pct),
                    mrr = result.metrics.mrr,
                    mrr_lift = format!("{:+.1}%", lift.mrr_lift_pct),
                    "Reranked results"
                );

                reports.push(QualityReport {
                    embedder: embedder.model_name().to_string(),
                    reranker: reranker.model_name().to_string(),
                    metrics: result.metrics,
                    lift_over_baseline: lift,
                    by_query_category: result.by_category,
                    latency: result.latency,
                });
            }
        }

        Ok(reports)
    }

    fn evaluate_pipeline(
        &self,
        embedder: &dyn Embedder,
        reranker: Option<&dyn Reranker>,
    ) -> Result<PipelineResult> {
        let mut metrics_accum = MetricsAccumulator::new();
        let mut category_accum: HashMap<QueryCategory, MetricsAccumulator> = HashMap::new();
        let mut latencies = Vec::new();

        for query in &self.queries {
            let start = Instant::now();

            // Retrieve
            let candidates = self.corpus.semantic_search(embedder, &query.text, 100)?;

            // Optionally rerank
            let final_results = if let Some(rr) = reranker {
                let texts: Vec<&str> = candidates.iter().map(|c| c.text.as_str()).collect();
                let scores = rr.rerank(&query.text, &texts)?;
                let mut scored: Vec<_> = candidates.into_iter().zip(scores).collect();
                scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
                scored.into_iter().map(|(c, _)| c).collect()
            } else {
                candidates
            };

            let elapsed = start.elapsed();
            latencies.push(elapsed.as_millis() as f64);

            // Compute metrics
            let result_ids: Vec<&str> = final_results.iter().map(|r| r.id.as_str()).collect();
            let relevance: Vec<bool> = result_ids.iter()
                .map(|id| query.relevant_ids.contains(*id))
                .collect();

            metrics_accum.add(&relevance);
            category_accum.entry(query.category.clone())
                .or_default()
                .add(&relevance);
        }

        Ok(PipelineResult {
            metrics: metrics_accum.finalize(),
            by_category: category_accum.into_iter()
                .map(|(k, v)| (k, v.finalize()))
                .collect(),
            latency: LatencyStats::from_millis(&latencies),
        })
    }
}

fn pct_lift(baseline: f64, improved: f64) -> f64 {
    if baseline == 0.0 { return 0.0; }
    ((improved - baseline) / baseline) * 100.0
}
```

### Statistical Significance
```rust
/// Bootstrap confidence interval for metric difference
pub fn bootstrap_significance(
    baseline_scores: &[f64],
    improved_scores: &[f64],
    n_bootstrap: usize,
) -> (f64, f64, bool) {
    let mut rng = rand::thread_rng();
    let n = baseline_scores.len();
    let mut diffs = Vec::with_capacity(n_bootstrap);

    for _ in 0..n_bootstrap {
        let indices: Vec<usize> = (0..n).map(|_| rng.gen_range(0..n)).collect();
        let base_mean: f64 = indices.iter().map(|&i| baseline_scores[i]).sum::<f64>() / n as f64;
        let imp_mean: f64 = indices.iter().map(|&i| improved_scores[i]).sum::<f64>() / n as f64;
        diffs.push(imp_mean - base_mean);
    }

    diffs.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let ci_low = diffs[n_bootstrap * 5 / 100];   // 5th percentile
    let ci_high = diffs[n_bootstrap * 95 / 100]; // 95th percentile
    let significant = ci_low > 0.0; // Entire CI above 0 = significant improvement

    (ci_low, ci_high, significant)
}
